  const tl = t.toLowerCase(); const all = tl + ' ' + (snippet||'').toLowerCase();
  if (/\b(managing director|country manager|general manager|directeur general|dga)\b/.test(tl)) return 8;
  if (/\b(head of|vp|vice.?president|svp|evp|director|directeur|directrice)\b/.test(tl))
