function scoreComm(t, snippet) {
  const tl = t.toLowerCase(); const all = tl + ' ' + (snippet||'').toLowerCase();
  if (/\b(ceo|cto|coo|cfo|chief|directeur|director|head of|vp|vice.?president|manager|responsable|lead|senior|chef de projet|charge de mission)\b/.test(tl)) return 0;
  let s = 0;
