  else if (/\b(promo 202[4-6]|class of 202[4-6]|m2|master 2|m1|bachelor)\b/.test(all)) s += 6;
  else if (/\b(promo 202[2-3]|class of 202[2-3]|junior|debutant|recemment diplome|jeune diplome)\b/.test(all)) s += 4;
  if (/\b(hec paris|essec|escp|polytechnique|centralesupelec|mines paris|sciences.?po)\b/.test(all)) s += 3;
  else if (/\b(edhec|skema|emlyon|neoma|audencia|kedge|insa|epitech|efrei)\b/.test(all)) s += 2;
  if (/\b(data|growth|digital|gtm|marketing|ai|ia|no.?code|automation|product)\b/.test(all)) s += 1;
  return Math.min(s, 10);
}
